import json
import asyncio
import time
from pathlib import Path
from typing import Dict, List, Optional, Tuple, Any
from dataclasses import dataclass, asdict
from datetime import datetime, timedelta
from collections import defaultdict

from .config import Config
from .atomic_writer import AtomicWriter, atomic_session_write

@dataclass
class SessionAnalytics:
    """Analytics data for a conversation session"""
    session_id: str
    model_name: str
    start_time: str
    end_time: Optional[str] = None
    total_interactions: int = 0
    avg_response_time: float = 0.0
    primary_intent_types: List[str] = None
    route_distribution: Dict[str, int] = None
    context_compression_stats: Dict[str, float] = None
    tool_usage_frequency: Dict[str, int] = None
    session_quality_score: float = 0.0
    performance_metrics: Dict[str, float] = None

    def __post_init__(self):
        if self.primary_intent_types is None:
            self.primary_intent_types = []
        if self.route_distribution is None:
            self.route_distribution = {}
        if self.context_compression_stats is None:
            self.context_compression_stats = {}
        if self.tool_usage_frequency is None:
            self.tool_usage_frequency = {}
        if self.performance_metrics is None:
            self.performance_metrics = {}

@dataclass
class SessionMetadata:
    """Enhanced metadata for session management"""
    session_id: str
    model_name: str
    created_at: str
    last_updated: str
    entry_count: int = 0
    session_type: str = "interactive"  # interactive, batch, tool_heavy, etc.
    complexity_level: str = "standard"  # simple, standard, complex, expert
    dominant_intent: str = "unknown"
    performance_profile: Dict[str, float] = None
    context_efficiency: float = 0.0
    user_satisfaction_indicators: Dict[str, int] = None

    def __post_init__(self):
        if self.performance_profile is None:
            self.performance_profile = {}
        if self.user_satisfaction_indicators is None:
            self.user_satisfaction_indicators = {}

class IntelligentSessionManager:
    """Enhanced session management with intelligence and analytics"""

    def __init__(self, config: Config):
        self.config = config

        # Directory structure
        self.base_dir = Path('logs')
        self.sessions_dir = self.base_dir / 'sessions'
        self.analytics_dir = self.base_dir / 'analytics'
        self.intelligence_dir = self.base_dir / 'intelligence'
        self.backup_dir = self.base_dir / 'backups'

        # Create enhanced directory structure
        for dir_path in [self.sessions_dir, self.analytics_dir, self.intelligence_dir, self.backup_dir]:
            dir_path.mkdir(parents=True, exist_ok=True)

        # Initialize atomic writer
        self.atomic_writer = AtomicWriter(str(self.backup_dir))

        # Model-specific organization
        self.model_name = config.model.name.replace(':', '-').replace('/', '-')
        self.model_dir = self.sessions_dir / self.model_name
        self.model_analytics_dir = self.analytics_dir / self.model_name
        self.model_intelligence_dir = self.intelligence_dir / self.model_name

        for dir_path in [self.model_dir, self.model_analytics_dir, self.model_intelligence_dir]:
            dir_path.mkdir(exist_ok=True)

        # Session tracking
        self.current_session_id = None
        self.session_start_time = None
        self.current_metadata = None
        self.session_analytics = None

        # Performance tracking
        self.interaction_times = []
        self.route_usage = defaultdict(int)
        self.intent_tracking = defaultdict(int)
        self.context_stats = []

    def create_intelligent_session(self, session_type: str = "interactive") -> str:
        """Create a new session with intelligence-based classification"""
        timestamp = datetime.now()
        session_id = f"{self.model_name}_{timestamp.strftime('%Y%m%d_%H%M%S')}"

        # Initialize session metadata
        self.current_session_id = session_id
        self.session_start_time = timestamp

        self.current_metadata = SessionMetadata(
            session_id=session_id,
            model_name=self.model_name,
            created_at=timestamp.isoformat(),
            last_updated=timestamp.isoformat(),
            session_type=session_type
        )

        self.session_analytics = SessionAnalytics(
            session_id=session_id,
            model_name=self.model_name,
            start_time=timestamp.isoformat()
        )

        # Reset tracking data
        self.interaction_times = []
        self.route_usage = defaultdict(int)
        self.intent_tracking = defaultdict(int)
        self.context_stats = []

        return session_id

    def update_session_intelligence(self, metadata: Dict):
        """Update session with routing and performance metadata"""
        if not self.current_metadata:
            return

        # Track routing usage
        if 'route_lane' in metadata:
            self.route_usage[metadata['route_lane']] += 1

        # Track intent patterns
        if 'intent_type' in metadata:
            self.intent_tracking[metadata['intent_type']] += 1

        # Track context efficiency
        if 'context_compression' in metadata:
            self.context_stats.append(metadata['context_compression'])

        # Update dominant patterns
        self._update_dominant_patterns()

        # Update session complexity based on patterns
        self._classify_session_complexity()

    def _update_dominant_patterns(self):
        """Update dominant intent and route patterns"""
        if self.intent_tracking:
            self.current_metadata.dominant_intent = max(
                self.intent_tracking.items(), key=lambda x: x[1]
            )[0]

        # Update analytics
        self.session_analytics.route_distribution = dict(self.route_usage)
        self.session_analytics.primary_intent_types = list(
            sorted(self.intent_tracking.keys(), key=lambda x: self.intent_tracking[x], reverse=True)[:3]
        )

    def _classify_session_complexity(self):
        """Classify session complexity based on usage patterns"""
        total_interactions = sum(self.route_usage.values())
        if total_interactions == 0:
            return

        # Complexity indicators
        deliberate_ratio = self.route_usage.get('deliberate', 0) / total_interactions
        tool_usage_ratio = self.route_usage.get('tool_use', 0) / total_interactions
        intent_diversity = len(self.intent_tracking)

        if deliberate_ratio > 0.3 or tool_usage_ratio > 0.4 or intent_diversity > 5:
            complexity = "expert"
        elif deliberate_ratio > 0.15 or tool_usage_ratio > 0.2 or intent_diversity > 3:
            complexity = "complex"
        elif deliberate_ratio > 0.05 or tool_usage_ratio > 0.1 or intent_diversity > 1:
            complexity = "standard"
        else:
            complexity = "simple"

        self.current_metadata.complexity_level = complexity

    def calculate_session_quality_score(self) -> float:
        """Calculate quality score based on performance metrics"""
        if not self.current_metadata or not self.session_analytics:
            return 0.0

        score_components = []

        # Response consistency (measured by route confidence)
        if hasattr(self, 'route_confidences') and self.route_confidences:
            avg_confidence = sum(self.route_confidences) / len(self.route_confidences)
            score_components.append(avg_confidence * 30)  # 30% weight

        # Context efficiency
        if self.context_stats:
            avg_efficiency = sum(self.context_stats) / len(self.context_stats)
            score_components.append(avg_efficiency * 25)  # 25% weight

        # Intent classification accuracy (proxy: diversity indicates good coverage)
        intent_score = min(len(self.intent_tracking) * 10, 100)  # Max 100 for 10+ intents
        score_components.append(intent_score * 20 / 100)  # 20% weight

        # Session engagement (interactions per time)
        if self.session_start_time:
            duration = (datetime.now() - self.session_start_time).total_seconds() / 60  # minutes
            interactions = sum(self.route_usage.values())
            if duration > 0:
                engagement = min(interactions / duration * 10, 100)  # Normalize
                score_components.append(engagement * 25 / 100)  # 25% weight

        return sum(score_components) if score_components else 0.0

    def get_model_specific_insights(self) -> Dict:
        """Generate insights specific to the current model"""
        insights = {
            'model_name': self.model_name,
            'optimal_routes': [],
            'performance_patterns': {},
            'recommended_configurations': {}
        }

        if not self.route_usage:
            return insights

        total_interactions = sum(self.route_usage.values())

        # Identify optimal routes
        for route, count in self.route_usage.items():
            ratio = count / total_interactions
            if ratio > 0.2:  # Route used in >20% of interactions
                insights['optimal_routes'].append({
                    'route': route,
                    'usage_ratio': ratio,
                    'effectiveness': 'high' if ratio > 0.4 else 'moderate'
                })

        # Performance patterns
        insights['performance_patterns'] = {
            'route_diversity': len(self.route_usage),
            'complexity_level': self.current_metadata.complexity_level if self.current_metadata else 'unknown',
            'dominant_intent': self.current_metadata.dominant_intent if self.current_metadata else 'unknown'
        }

        # Model-specific recommendations
        insights['recommended_configurations'] = self._generate_model_recommendations()

        return insights

    def _generate_model_recommendations(self) -> Dict:
        """Generate configuration recommendations based on usage patterns"""
        recommendations = {}

        if not self.route_usage:
            return recommendations

        total = sum(self.route_usage.values())

        # Routing threshold recommendations
        if self.route_usage.get('deliberate', 0) / total > 0.3:
            recommendations['routing_thresholds'] = {
                'reasoning_threshold': 0.5,  # Lower for more deliberate routing
                'suggestion': 'High deliberate usage detected - consider lowering reasoning threshold'
            }

        # Context optimization recommendations
        if len(self.context_stats) > 5:
            avg_compression = sum(self.context_stats) / len(self.context_stats)
            if avg_compression < 0.6:
                recommendations['context_optimization'] = {
                    'enable_aggressive_pruning': True,
                    'max_context_tokens': int(self.config.optimization.max_context_tokens * 0.8),
                    'suggestion': 'Low context efficiency - consider more aggressive pruning'
                }

        return recommendations

    def save_session_analytics(self):
        """Save current session analytics and metadata using atomic writes"""
        if not self.current_session_id:
            return

        try:
            with atomic_session_write(self, str(self.backup_dir)) as writer:
                # Update final analytics
                if self.session_analytics:
                    self.session_analytics.end_time = datetime.now().isoformat()
                    self.session_analytics.total_interactions = sum(self.route_usage.values())
                    if self.interaction_times:
                        self.session_analytics.avg_response_time = sum(self.interaction_times) / len(self.interaction_times)
                    self.session_analytics.session_quality_score = self.calculate_session_quality_score()

                    # Context compression stats
                    if self.context_stats:
                        self.session_analytics.context_compression_stats = {
                            'avg_compression': sum(self.context_stats) / len(self.context_stats),
                            'min_compression': min(self.context_stats),
                            'max_compression': max(self.context_stats)
                        }

                # Save analytics file atomically
                analytics_file = self.model_analytics_dir / f"{self.current_session_id}_analytics.json"
                success = writer.write_json_atomic(str(analytics_file), asdict(self.session_analytics))
                if not success:
                    raise Exception("Failed to write analytics file")

                # Save metadata file atomically
                if self.current_metadata:
                    self.current_metadata.last_updated = datetime.now().isoformat()
                    metadata_file = self.model_dir / f"{self.current_session_id}_metadata.json"
                    success = writer.write_json_atomic(str(metadata_file), asdict(self.current_metadata))
                    if not success:
                        raise Exception("Failed to write metadata file")

                # Save model insights atomically
                insights = self.get_model_specific_insights()
                insights_file = self.model_intelligence_dir / f"{self.current_session_id}_insights.json"
                success = writer.write_json_atomic(str(insights_file), insights)
                if not success:
                    raise Exception("Failed to write insights file")

        except Exception as e:
            print(f"Warning: Failed to save session analytics atomically: {e}")
            # Fallback to non-atomic writes
            self._save_session_analytics_fallback()

    def _save_session_analytics_fallback(self):
        """Fallback method for saving session analytics without atomic writes"""
        try:
            # Save analytics file
            analytics_file = self.model_analytics_dir / f"{self.current_session_id}_analytics.json"
            with open(analytics_file, 'w') as f:
                json.dump(asdict(self.session_analytics), f, indent=2)

            # Save metadata file
            if self.current_metadata:
                metadata_file = self.model_dir / f"{self.current_session_id}_metadata.json"
                with open(metadata_file, 'w') as f:
                    json.dump(asdict(self.current_metadata), f, indent=2)

            # Save model insights
            insights = self.get_model_specific_insights()
            insights_file = self.model_intelligence_dir / f"{self.current_session_id}_insights.json"
            with open(insights_file, 'w') as f:
                json.dump(insights, f, indent=2)
        except Exception as e:
            print(f"Warning: Fallback session save also failed: {e}")

    def get_historical_performance(self, days: int = 7) -> Dict:
        """Get historical performance data for the model"""
        cutoff_date = datetime.now() - timedelta(days=days)
        performance_data = {
            'sessions_analyzed': 0,
            'avg_quality_score': 0.0,
            'route_preferences': defaultdict(int),
            'complexity_distribution': defaultdict(int),
            'performance_trends': []
        }

        # Analyze recent analytics files
        for analytics_file in self.model_analytics_dir.glob("*_analytics.json"):
            try:
                with open(analytics_file, 'r') as f:
                    analytics = json.load(f)

                session_date = datetime.fromisoformat(analytics['start_time'])
                if session_date >= cutoff_date:
                    performance_data['sessions_analyzed'] += 1
                    performance_data['avg_quality_score'] += analytics.get('session_quality_score', 0)

                    # Route distribution
                    for route, count in analytics.get('route_distribution', {}).items():
                        performance_data['route_preferences'][route] += count

            except Exception:
                continue

        # Calculate averages
        if performance_data['sessions_analyzed'] > 0:
            performance_data['avg_quality_score'] /= performance_data['sessions_analyzed']

        return dict(performance_data)

    def auto_optimize_configuration(self) -> Dict:
        """Automatically suggest configuration optimizations based on historical data"""
        historical = self.get_historical_performance()
        current_insights = self.get_model_specific_insights()

        optimizations = {
            'routing_config': {},
            'optimization_config': {},
            'justification': []
        }

        if historical['sessions_analyzed'] < 3:
            optimizations['justification'].append("Insufficient data for auto-optimization")
            return optimizations

        # Route threshold optimization
        route_prefs = historical['route_preferences']
        total_routes = sum(route_prefs.values())

        if total_routes > 0:
            deliberate_ratio = route_prefs.get('deliberate', 0) / total_routes
            if deliberate_ratio > 0.4:
                optimizations['routing_config']['reasoning_threshold'] = 0.5
                optimizations['justification'].append("High deliberate route usage - lowering reasoning threshold")
            elif deliberate_ratio < 0.1:
                optimizations['routing_config']['reasoning_threshold'] = 0.7
                optimizations['justification'].append("Low deliberate route usage - raising reasoning threshold")

        # Context optimization
        if historical['avg_quality_score'] < 70:
            optimizations['optimization_config']['dynamic_pruning'] = True
            optimizations['optimization_config']['max_context_tokens'] = int(self.config.optimization.max_context_tokens * 0.7)
            optimizations['justification'].append("Low quality scores - enabling aggressive context optimization")

        return optimizations

    def backup_session_data(self, session_id: Optional[str] = None) -> bool:
        """
        Create backup of session data for recovery purposes.

        Args:
            session_id: Specific session to backup, or current session if None

        Returns:
            True if backup successful
        """
        target_session_id = session_id or self.current_session_id
        if not target_session_id:
            return False

        try:
            # Backup analytics file
            analytics_file = self.model_analytics_dir / f"{target_session_id}_analytics.json"
            if analytics_file.exists():
                self.atomic_writer._create_backup(analytics_file)

            # Backup metadata file
            metadata_file = self.model_dir / f"{target_session_id}_metadata.json"
            if metadata_file.exists():
                self.atomic_writer._create_backup(metadata_file)

            # Backup insights file
            insights_file = self.model_intelligence_dir / f"{target_session_id}_insights.json"
            if insights_file.exists():
                self.atomic_writer._create_backup(insights_file)

            return True

        except Exception as e:
            print(f"Warning: Session backup failed: {e}")
            return False

    def restore_session_data(self, session_id: str, backup_timestamp: Optional[int] = None) -> bool:
        """
        Restore session data from backup.

        Args:
            session_id: Session to restore
            backup_timestamp: Specific backup timestamp, or latest if None

        Returns:
            True if restoration successful
        """
        try:
            success_count = 0

            # Restore analytics file
            analytics_file = self.model_analytics_dir / f"{session_id}_analytics.json"
            if self.atomic_writer.restore_from_backup(str(analytics_file), backup_timestamp):
                success_count += 1

            # Restore metadata file
            metadata_file = self.model_dir / f"{session_id}_metadata.json"
            if self.atomic_writer.restore_from_backup(str(metadata_file), backup_timestamp):
                success_count += 1

            # Restore insights file
            insights_file = self.model_intelligence_dir / f"{session_id}_insights.json"
            if self.atomic_writer.restore_from_backup(str(insights_file), backup_timestamp):
                success_count += 1

            return success_count > 0

        except Exception as e:
            print(f"Warning: Session restoration failed: {e}")
            return False

    def list_session_backups(self, session_id: Optional[str] = None) -> List[Dict]:
        """
        List available session backups.

        Args:
            session_id: Specific session to list backups for, or all if None

        Returns:
            List of backup information
        """
        if session_id:
            # List backups for specific session
            analytics_file = self.model_analytics_dir / f"{session_id}_analytics.json"
            metadata_file = self.model_dir / f"{session_id}_metadata.json"
            insights_file = self.model_intelligence_dir / f"{session_id}_insights.json"

            all_backups = []
            for file_path in [analytics_file, metadata_file, insights_file]:
                backups = self.atomic_writer.list_backups(str(file_path))
                all_backups.extend(backups)

            return all_backups
        else:
            # List all session backups
            return self.atomic_writer.list_backups()

    def cleanup_session_backups(self, keep_count: int = 5) -> int:
        """
        Clean up old session backups.

        Args:
            keep_count: Number of recent backups to keep per file

        Returns:
            Number of backups deleted
        """
        return self.atomic_writer.cleanup_old_backups(keep_count)

    def get_session_recovery_info(self) -> Dict[str, Any]:
        """Get information about session recovery capabilities"""
        backup_stats = {
            'backup_directory': str(self.backup_dir),
            'available_backups': len(self.atomic_writer.list_backups()),
            'current_session_backed_up': False,
            'recovery_options': []
        }

        if self.current_session_id:
            session_backups = self.list_session_backups(self.current_session_id)
            backup_stats['current_session_backed_up'] = len(session_backups) > 0
            backup_stats['current_session_backup_count'] = len(session_backups)

            # Check for recent sessions that can be recovered
            recent_backups = [b for b in session_backups if b['timestamp'] and
                            (time.time() - b['timestamp']) < 3600]  # Last hour
            backup_stats['recent_recoverable_sessions'] = len(recent_backups)

        return backup_stats